INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'GFH-1', 'ビームラックル(H・L・C形鋼用) 空気管用', 'H・L形鋼(鋼材厚20mm迄) C形鋼(ツバ20mm迄)。防災機器等の取り付けに使用します。空気管支持専用なので、碍子等のセットが不要です。空気管挟み方式なので、バインド止めが不要です。', 820, 'https://dummyimage.com/200x200/cccccc/000.png&text=GFH-1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 30, 80.5, 20.5);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'GFH-2', 'ビームラックル(H・L・C形鋼用) 空気管用', 'H・L形鋼(鋼材厚20mm迄) C形鋼(ツバ20mm迄)。防災機器等の取り付けに使用します。空気管碍子の固定できない所で威力を発揮します。空気管をメッセンジャーワイヤーに抱き合わせ鋼材に対して、平行に施工する場合に使用します。', 620, 'https://dummyimage.com/200x200/cccccc/000.png&text=GFH-2', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 30, 87.5, 20.5);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'GFH-3', 'ビームラックル(H・L・C形鋼用) 空気管用', 'H・L形鋼(鋼材厚20mm迄) C形鋼(ツバ20mm迄)。防災機器等の取り付けに使用します。空気管碍子の固定できない所で威力を発揮します。空気管をメッセンジャーワイヤーに抱き合わせ鋼材に対して、直角に施工する場合に使用します。', 620, 'https://dummyimage.com/200x200/cccccc/000.png&text=GFH-3', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 30, 70, 20);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SLC-1', 'ビームラックル(H・L・C形鋼・吊りボルト用) 樹脂製', 'H・L・C形鋼・吊りボルト。蛍光灯・配線器具・火災感知器等の取り付けに使用します。結束バンド・サドルを使用し、配管材・ケーブル等の固定もできます。金具の向きを付け替えることで適合鋼材の変更ができます。適合ビス: サイズ: Φ3.5~Φ4.1 長さ: 10~16.5mm迄', 340, 'https://dummyimage.com/200x200/cccccc/000.png&text=SLC-1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 67, 22, 78);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SL-1', 'ビームラックル(H・L・C形鋼・吊りボルト用) 樹脂製', 'H・L形鋼(鋼材厚4~7mm) 吊りボルト(W3/8-W1/2)。蛍光灯・配線器具等の取り付けに使用します。適合ビス: サイズ: Φ3.5~Φ4.1 長さ: 10~13.5mm迄', 340, 'https://dummyimage.com/200x200/cccccc/000.png&text=SL-1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 84, 22, 46);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SGM', '形鋼金具 H・L形鋼用', 'H・L形鋼(鋼材厚30mm迄)。ミラックハンガーと組み合わせて、照明器具・電線管等を取り付ける場合に使用します。吊りボルトを下げ、ラック・ダクト等の支持に使用します。', 340, 'https://dummyimage.com/200x200/cccccc/000.png&text=SGM', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 60, 86.8, 35);
