INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'YKTF-W2', 'ターンバックル (連結金具付、電気亜鉛めっき仕様)', '両側アイボルトタイプ。駅構内など電車の振動でゆるむ可能性のある所に使用。連結金具付を使えば、ターンバックルを直接アイボルトに固定できる。ゆるみ止め付ナット(M6)はフリクションリング付。破断荷重: 7840N(800kgf)以上。', 800, 'https://dummyimage.com/200x200/cccccc/000.png&text=YKTF-W2', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 10.5, 10.5, 97);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'YKH-TB', 'ワイヤー支持金具 (電気亜鉛めっき仕様)', '振れ止め又は、メッセンジャーワイヤー、ミラックラダーHを吊りボルト等で支持する場合に使用。適合ワイヤー径: Φ4.8～Φ9.6 (メッセンジャーワイヤー: 14sq～55sq)。許容静荷重: 980N(100kgf)。最大ワイヤー保持力: 98N(10kgf)。締付トルク: 7.84N-m(80kgf-cm)。', 630, 'https://dummyimage.com/200x200/cccccc/000.png&text=YKH-TB', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 50, 35, 22);
