INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DLA-150', 'ダウンライト台座 (UR都市機構仕様)', '適合開口穴150mm。D1: 176mm, D2: 150mm。ダウンライトを薄い金属化粧板(スパンドレル)等、厚みのない天井板へ取り付ける場合に使用。リフォーム等で既存のダウンライト開口穴を再利用する場合のせっこうボードの修復としても使用。', 560, 'https://dummyimage.com/200x200/cccccc/000.png&text=DLA-150', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 176, 10, 176);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DLAF-50-75', 'ダウンライト台座 (フリータイプ、スパンドレル用)', 'ダウンライトをスパンドレル(金属化粧板)等へ取り付ける場合に使用。小口径のダウンライト開口穴にも施工しやすい形状。工具も取り付けねじも不要なスライド固定式。簡単に施工できる。取付板(ボード)厚: 0.5mm～1.5mm。適合開口穴: Φ50～Φ75。', 520, 'https://dummyimage.com/200x200/cccccc/000.png&text=DLAF-50-75', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 98, 10, 75);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DLAS-50-75', 'ダウンライト台座 (フリータイプ、ロックウール化粧吸音板用)', 'ダウンライトをスパンドレル(金属化粧板)等へ取り付ける場合に使用。小口径のダウンライト開口穴にも施工しやすい形状。工具も取り付けねじも不要なスライド固定式。簡単に施工できる。取付板(ボード)厚: 9mm～。適合開口穴: Φ50～Φ75。', 520, 'https://dummyimage.com/200x200/cccccc/000.png&text=DLAS-50-75', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 98, 16.2, 75);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DLBP-100', 'ブランクプレート (カベ白)', '色: カベ白。適用: 天井用。適合穴径: Φ50～Φ100。適合天井厚: 25mm迄。ダウンライト等を取り外した際の天井の不要な穴を塞ぐためのプレート。ばねを天井に引っ掛けるだけの簡単取り付け。', 840, 'https://dummyimage.com/200x200/cccccc/000.png&text=DLBP-100', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 120, 31, 120);
