INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DLBPK-L', 'ブランクプレート (角型、カベ白)', '色: カベ白。天井の不要な四角穴を塞ぐためのプレート。ばねを天井に引っ掛けるだけの簡単取り付け。傾斜天井や、壁面にも取り付け可能。適合開口: 200～300mm。適合天井厚: 25mm迄。', 2980, 'https://dummyimage.com/200x200/cccccc/000.png&text=DLBPK-L', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 325, 4.5, 325);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'NBS-DL', 'ダウンライトアッター', '野ぶちに取り付けるだけ。磁石探知器を使用してダウンライトの穴あけ位置が簡単に探知できる。取り付け位置(穴あけ位置)は自在に設定可能。くり返し使用可能。強力磁石付。', 640, 'https://dummyimage.com/200x200/cccccc/000.png&text=NBS-DL', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 50.5, 40, 300);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DLR-125W', 'リニューアルプレート (カベ白)', '色: カベ白。適合天井厚: 0.5～25mm。既存のダウンライトをサイズダウンする場合の穴径を縮める場合に使用。ブランクカバーとしても使用。既存取付穴径: Φ125～Φ127。取付ダウンライト径: Φ100、Φ75。許容静荷重: 19.6N(2kgf)。', 2500, 'https://dummyimage.com/200x200/cccccc/000.png&text=DLR-125W', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 180, 38.5, 180);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DLR-150W', 'リニューアルプレート (カベ白)', '色: カベ白。適合天井厚: 0.5～25mm。既存のダウンライトをサイズダウンする場合の穴径を縮める場合に使用。ブランクカバーとしても使用。既存取付穴径: Φ150～Φ152。取付ダウンライト径: Φ125、Φ100、Φ75。許容静荷重: 19.6N(2kgf)。', 2800, 'https://dummyimage.com/200x200/cccccc/000.png&text=DLR-150W', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 200, 38.5, 200);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DLC-2512SA', '気密カバー (ダウンライト用、粘着テープ付)', '粘着テープ付。気密性を要する二重天井へのSB形ダウンライト取り付けに使用。先行取り付けなので、天井板施工後従来同様の工事が可能。適用機器: SB形ダウンライト。適用開口径: 125迄。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=DLC-2512SA', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 331, 120, 331);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DLC-2512SA-N', '気密カバー (ダウンライト用、粘着テープ無)', '粘着テープ無。気密性を要する二重天井へのSB形ダウンライト取り付けに使用。先行取り付けなので、天井板施工後従来同様の工事が可能。適用機器: SB形ダウンライト。適用開口径: 125迄。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=DLC-2512SA-N', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 331, 120, 331);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'K-HLC', '感知器専用台座 (H・L・C形鋼用、RoHS対応)', 'H・L・C形鋼への感知器の取り付けに使用。予めビスがセットされており、ベースへの取り付けが容易。適合寸法(A): H・L形鋼(鋼材厚20mm迄)、C形鋼(ツバ20mm迄)。許容静荷重: 9.8N(1kgf)。', 640, 'https://dummyimage.com/200x200/cccccc/000.png&text=K-HLC', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 66.7, 61.5, 110);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'K-BT', '感知器専用台座 (吊りボルト用、RoHS対応)', '吊りボルトへの感知器の取り付けに使用。予めビスがセットされており、ベースへの取り付けが容易。適合ボルト: W3/8-W1/2-M10-M12。許容静荷重: 9.8N(1kgf)。', 300, 'https://dummyimage.com/200x200/cccccc/000.png&text=K-BT', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 66.7, 61.5, 110);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'GGKB', '感知器用台座 (鋲打機用)', '天井等への感知器の取り付けに使用。鋲打機で簡単に取り付け可能。予めビスがセットされており、ベースへの取り付けが容易。ビスを38mmピッチのビス穴に付け替えればボックスの取り付けも可能。適合: 電気式・ガス式鋲打機。', 300, 'https://dummyimage.com/200x200/cccccc/000.png&text=GGKB', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 66.7, 22, 147.5);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'K-B', '感知器専用台座 (ビス止めタイプ、RoHS対応)', '壁面等への感知器の取り付けに使用。予めビスがセットされており、ベースへの取り付けが容易。適合ビス: Φ3.1～Φ4.1。許容静荷重: 9.8N(1kgf)。', 210, 'https://dummyimage.com/200x200/cccccc/000.png&text=K-B', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 66.7, 61.5, 110);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'KTT-1', '感知器用高さ調整台座', 'H形鋼に感知器を設置する際に、感知器の高さを約100mm上げて設置。形鋼金具と組み合わせ、鋼材に感知器を固定する場合に使用。適合: 形鋼金具(SGK-SGKL)。許容静荷重: 1.96N(200gf)。', 1000, 'https://dummyimage.com/200x200/cccccc/000.png&text=KTT-1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 66.7, 160, 250);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SGPB-10K', '角パイプ用感知器金具 (RoHS対応)', '角パイプの小梁へ感知器を取り付ける場合に使用。角パイプに簡単に取り付け可能。解除も可能。金具上面では結束バンドによるケーブルの固定が可能。適合: 角パイプ100用。許容静荷重: 4.9N(0.5kgf)。', 1000, 'https://dummyimage.com/200x200/cccccc/000.png&text=SGPB-10K', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 66.7, 38, 234);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SBP-KL', 'パネルボックス (感知器用、取付ボード厚3～25mm迄)', '色: カベ白。感知器取り付け用のパネルボックス。商用電源を使用しない感知器、天井スピーカーの配線ボックスに便利。塵、ほこり、ねずみの糞尿等による感知器の誤動作を防止。丸形プレートが取り付き。取付ボード厚: 3～25mm迄。取付孔: ホルソー径Φ77～Φ80。感知器フランジ外径: Φ100～Φ104。感知器取付ピッチ: 66.7mm。適合丸形プレート: Φ105。', 450, 'https://dummyimage.com/200x200/cccccc/000.png&text=SBP-KL', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 102, 28, 33.7);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SBP-K', 'パネルボックス (感知器用、弱電用、取付ボード厚3～18mm迄)', '色: カベ白。感知器取り付け用のパネルボックス。商用電源を使用しない感知器、天井スピーカーの配線ボックスに便利。塵、ほこり、ねずみの糞尿等による感知器の誤動作を防止。取付ボード厚: 3～18mm迄。取付孔: ホルソー径Φ63.5(2 1/2in)。感知器フランジ外径: Φ92～Φ104。感知器取付ピッチ: 66.7mm。', 380, 'https://dummyimage.com/200x200/cccccc/000.png&text=SBP-K', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 102, 28, 33.7);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'OF-11PD', '感知器用はさみ枠 (粘着テープ付)', '色: グレー。天井への感知器等の取り付け台座として使用。引き回しノコのけ書きガイド(ポイント穴)付。天井への仮固定ができる粘着テープ付。SBホルソーを使用すれば穴あけが簡単で速い。適合: 固定ピッチ66.7mmの感知器、器具等。', 230, 'https://dummyimage.com/200x200/cccccc/000.png&text=OF-11PD', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 120, 10, 120);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'OF-MC89', '丸形ボックスカバー (器具用)', '丸形ボックスにスピーカー等の器具を取り付ける場合に使用。座金付なべ小ねじ(M4)×2、十字穴付超低頭小ねじ(M4)×2付。適合ボックス: 樹脂製丸形ボックス(JIS C8435に適合する呼び22以下)、鉄製・鋳鉄製丸形ボックス(JIS C8340に適合する呼び22、25以下)。許容静荷重: 29N(3kgf)。', 720, 'https://dummyimage.com/200x200/cccccc/000.png&text=OF-MC89', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 89, 66.7, 89);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'KKK-BW', 'カメラ・感知器兼用台座', '屋内用の小型防犯カメラや感知器の取り付けに使用します。台座の薄肉部をナイフ等でカットすれば、モールを取り付けられます。色:白。', 620, 'https://dummyimage.com/200x200/cccccc/000.png&text=KKK-BW', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 110, 16, 110);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'K-BC', '感知器用防滴カバー', 'コーキング等施すことなく、感知器を結露水から防ぐカバーです。通線部のブッシングには配線用の薄バリが設けてあります。更に電源側と送り側に分けて入線できます。適合台座: K-B、K-BT、K-HLC、GGKB。', 980, 'https://dummyimage.com/200x200/cccccc/000.png&text=K-BC', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 130, 66.7, 130);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'PVM16-TJ', '露出丸型ボックス(1~3方出兼用型)', '感知器、コンセント取付用の木ねじ溝付です。キャップ2個付。高耐候性、耐衝撃性HI。色:ベージュ。適合管: VE14-16 (1~3方出兼用)。', 770, 'https://dummyimage.com/200x200/cccccc/000.png&text=PVM16-TJ', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 110, 107.5, 110);
