INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'PVM-OYT', '露出用丸型ボックス(ブランクタイプ) 1~4方出兼用型', '感知器、コンセントの取付用の木ねじ溝付です。添付の異径アダプターにより、2号コネクタが接続できます。ボックスと蓋の境目が無いスマートなデザインです。封印ビスが取り付けられます。高耐候性、耐衝撃性HI。2号コネクタ用異径アダプター2個、CDジョイントナット2個付。色:グレー。適合コネクタサイズ: G1 (28)、16・22(異径アダプター使用)。', 940, 'https://dummyimage.com/200x200/cccccc/000.png&text=PVM-OYT', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 106, 100, 106);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'BZ-KCRS', '高気密パッキン(感知器用)', 'ビスピッチ66.7mmの感知器用。クリーンルーム、高気密物件への感知器取り付けに使用します。適用警報用電線: 0.9mm、1.2mm。規格: 丸型塗代。', 1420, 'https://dummyimage.com/200x200/cccccc/000.png&text=BZ-KCRS', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 100, 37, 100);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'BZ-KCRS2', '高気密パッキン(人感センサー用)', 'クリーンルーム、高気密物件への人感センサー取り付けに使用します。適合ボックス: 鉄アウトレットボックス〈中形四角(深型)〉(OF-MB-1N・OF-MB-4N)。ボード表面からボックス内底面までの距離が60mm以上必要です。', 3840, 'https://dummyimage.com/200x200/cccccc/000.png&text=BZ-KCRS2', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 106, 83.5, 106);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'ZSG-M5', '絶縁支持具', '絶縁離隔が15㎜確保できる支持具です。屋外で使用できます。GPSアンテナの取り付けに最適です。適合ねじ: M5×14mm迄。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=ZSG-M5', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 20, 40, 20);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'STEW-45', '視柱®', '地中配管用。防犯カメラ等の小型器具設置用の鋼管です。架空配線、地中配管用の引出口が設けてあり、ボックスの取り付け、ケーブルの引き込みが容易。カメラ周りの配線が露出せず、美しい仕上がり。溶融亜鉛めっき加工により高い耐食性。上柱と下柱に分かれており、出荷時は下柱内に上柱が収納。', 64500, 'https://dummyimage.com/200x200/cccccc/000.png&text=STEW-45', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 76.3, 3200, 76.3);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'STEW-62', '視柱®', '架空配線用/地中配管用。防犯カメラ等の小型器具設置用の鋼管です。架空配線、地中配管用の引出口が設けてあり、ボックスの取り付け、ケーブルの引き込みが容易。カメラ周りの配線が露出せず、美しい仕上がり。溶融亜鉛めっき加工により高い耐食性。上柱と下柱に分かれており、出荷時は下柱内に上柱が収納。', 80300, 'https://dummyimage.com/200x200/cccccc/000.png&text=STEW-62', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 89.1, 4650, 89.1);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'STEW-BDDG', 'ボックス用台座(視柱用)', '視柱にボックスを取り付ける場合に使用します。バンド通し穴(10mm)が設けてあり、引出口以外でもバンドを使用して取り付けられます。色:ダークグレー。適合曲がりコネクタ: FNVK-16G、FNVK-22G。', 2490, 'https://dummyimage.com/200x200/cccccc/000.png&text=STEW-BDDG', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 110, 130, 110);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'STEW-BC1', '防水コンセント用台座(視柱用)', '視柱に防水コンセントを取り付ける台座です。本体:ステンレス製、パッキン:EPDM。ドリルねじ(4×40)2本、皿小ねじ(M4×16)2本付。適合鋼管ポール: 視柱(STEW-45,62)下柱Φ89.1。適合防水コンセント: 幅87mm以下。', 5150, 'https://dummyimage.com/200x200/cccccc/000.png&text=STEW-BC1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 87, 133.5, 50);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'STEW-ECJ', 'エントランスカバー(視柱用)', '視柱内にケーブルを引き込む場合に使用します。色:ベージュ。適合ケーブル: Φ12以下のケーブル×1、ノックを抜いた場合Φ14以下のケーブル×1又はΦ10.5以下のケーブル×2。適合コネクタ: 視柱内配管(MFSK-16G, FNVK-16G, FNVK-22G)、露出配管(MFSK-22G, FPK-16Y, FPK-22Y)。', 2140, 'https://dummyimage.com/200x200/cccccc/000.png&text=STEW-ECJ', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 73, 120, 73);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'STEW-HB', '引込バンド(視柱用)', '電柱から視柱に電源等を引き込む場合の引留め金具として使用します。溶融亜鉛めっき仕様。適合: STEW-62用。', 2740, 'https://dummyimage.com/200x200/cccccc/000.png&text=STEW-HB', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 208, 179, 112);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'STEW-C', '管端キャップ(視柱用)', '視柱の端末用キャップです。適用: 視柱(STEW-45、STEW-62)、ねじ無し電線管(E75)、薄鋼電線管(C75)。', 750, 'https://dummyimage.com/200x200/cccccc/000.png&text=STEW-C', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 82, 45, 82);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'STEW-A30K', '視柱(軽量タイプ)', '防犯カメラが4台取り付けられるパラソルボックスと組み合わせて使用するアルミ製軽量ポールです。全長3m。車の荷室に積み込めます。パラソルボックス内にはケーブルや結線部、ACアダプタ等が収納できます。視柱接続部にはコネクタが2個取り付けてあり、同梱のPF管が容易に配管できます。アルミ製:黒。アース用ねじ、座金付。', 57500, 'https://dummyimage.com/200x200/cccccc/000.png&text=STEW-A30K', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, 3000, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'STEW-PBK', 'パラソルボックス®', '樹脂製:シルバー。カメラ取り付け面:黒。アプセットボルト(4本)、PF管22(3m×2本)、絶縁キャップ(12個)付。適合防犯カメラの仕様: 取り付けねじピッチΦ42~91、取り付けフランジ径Φ100以下、全長250mm以下の小型カメラ。', 28700, 'https://dummyimage.com/200x200/cccccc/000.png&text=STEW-PBK', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 469, 218, 469);
