INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SGM', '形鋼金具 H・L形鋼用 (電気亜鉛めっき仕様)', 'ミラックハンガーと組み合わせて、照明器具・電線管等を取り付ける場合に使用します。吊りボルトを下げ、ラック・ダクト等の支持に使用します。底面の取付穴を利用して、照明器具等の取り付けに使用します。ダクトクリップを使用し、VE管・PF管の固定に使用します。電気亜鉛めっき仕様。', 340, 'https://dummyimage.com/200x200/cccccc/000.png&text=SGM', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 33, 60, 25);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SGMD', '形鋼金具 H・L形鋼用 (溶融めっき仕様)', 'ミラックハンガーと組み合わせて、照明器具・電線管等を取り付ける場合に使用します。吊りボルトを下げ、ラック・ダクト等の支持に使用します。底面の取付穴を利用して、照明器具等の取り付けに使用します。ダクトクリップを使用し、VE管・PF管の固定に使用します。溶融めっき仕様。', 750, 'https://dummyimage.com/200x200/cccccc/000.png&text=SGMD', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 33, 60, 25);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SGMS', '形鋼金具 H・L形鋼用 (ステンレス仕様)', 'ミラックハンガーと組み合わせて、照明器具・電線管等を取り付ける場合に使用します。吊りボルトを下げ、ラック・ダクト等の支持に使用します。底面の取付穴を利用して、照明器具等の取り付けに使用します。ダクトクリップを使用し、VE管・PF管の固定に使用します。ステンレス仕様。', 1230, 'https://dummyimage.com/200x200/cccccc/000.png&text=SGMS', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 33, 60, 25);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SGM-30', 'ビームラックル(H形鋼用) (電気亜鉛めっき仕様)', '形鋼金具、ミラックハンガー組付品です。取付ピッチ:90~100、170以外の取付方法。ミラックハンガーを背合わせで固定することにより取り付けられます。※照明器具の取り付けには、プレート・ナットをご使用ください。※ミラックハンガー部は高耐食めっき鋼板。許容静荷重:981N (100kgf) (30°迄), 490N (50kgf) (30°迄)。電気亜鉛めっき仕様。', 1300, 'https://dummyimage.com/200x200/cccccc/000.png&text=SGM-30', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 300, 30, 270);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SGM-40', 'ビームラックル(H形鋼用) (電気亜鉛めっき仕様)', '形鋼金具、ミラックハンガー組付品です。取付ピッチ:90~100、170以外の取付方法。ミラックハンガーを背合わせで固定することにより取り付けられます。※照明器具の取り付けには、プレート・ナットをご使用ください。※ミラックハンガー部は高耐食めっき鋼板。許容静荷重:981N (100kgf) (30°迄), 490N (50kgf) (30°迄)。電気亜鉛めっき仕様。', 1460, 'https://dummyimage.com/200x200/cccccc/000.png&text=SGM-40', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 400, 30, 370);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'ALCN-3B', 'ALC用フランジナット', 'ミラックハンガー等をALC壁にボルトで挟み固定する場合に使用します。(1人で作業できます。)市販のW3/8ボルトをカットして使用することで、壁厚に自在に対応できます。20個入。許容静荷重:196N(20kgf)。', 590, 'https://dummyimage.com/200x200/cccccc/000.png&text=ALCN-3B', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 94, 13, 94);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'KHC-B', '仮保持クリップ', '吊りボルトにハンガー等を仮保持する場合に使用。吊りボルトに挟み込むだけの簡単取り付け。磁石付なので、ハンガー等が滑り落ちにくい。(段差付なのでさらに安心)。紐通し穴あり。適合ボルト: W3/8-W1/2。入数: 1組。許容静荷重: 2個1組/20N(2kgf), 1個/9.8N(1kgf)。', 2370, 'https://dummyimage.com/200x200/cccccc/000.png&text=KHC-B', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 85, 36, 32);
