INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'LD-CBW', 'ライティングダクト用クリップベース', 'ライティングダクトにケーブルや管等の取り付け(支持)に使用。結束バンド、タッピンねじでの支持も可能。許容静荷重: クリップ部: 9.8N (1kgf), ベース部、ねじ穴部: 9.8N (1kgf)。適合: 電源ケーブル: φ2.5~φ3, LANケーブル、同軸ケーブル: φ5~φ7.5, 電源ケーブル: φ4, 結束バンド幅: 15mm迄, タッピンねじ: φ4 (ねじ長さ: 取付物の厚み+8mm~14mm)。色: カベ白。', 180, 'https://dummyimage.com/200x200/cccccc/000.png&text=LD-CBW', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 35.3, 28.2, 15.8);
