INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'XS40-FP', 'フロアーパネル', '適合システム: XS40P. PP製. 下地床に敷くだけの置き敷きタイプですから、施工がいたって簡単です。軽量、コンパクトですから施工がラクに行えます。また、搬入搬出にエレベーターや狭い階段等を使用しなければならない場合にも効率良い作業が行えます。切断に大型工具や専用工具を必要としません。また、カッターナイフで1/4にカットできます。電動丸のこ等での切断時にマスクをするほどの有害な粉塵は発生しません。重量(パネル1枚): 約1530g.', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=XS40-FP', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 500, 34.5, 500);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'XS50-FP', 'フロアーパネル', '適合システム: XS50P. PP製. 下地床に敷くだけの置き敷きタイプですから、施工がいたって簡単です。軽量、コンパクトですから施工がラクに行えます。また、搬入搬出にエレベーターや狭い階段等を使用しなければならない場合にも効率良い作業ができます。切断に大型工具や専用工具を必要としません。また、カッターナイフで1/4にカットできます。電動丸のこ等での切断時にマスクをするほどの有害な粉塵は発生しません。重量(パネル1枚): 約1680g.', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=XS50-FP', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 500, 44.5, 500);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'XY-SS', '消音シート', '発泡PE製. 下地床に敷き詰め、その上にフロアーパネルを施工します。規格: 1m幅×50m×2mm. 重量: 3300g.', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=XY-SS', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 1000, 2, 50000);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'XS50-BP', 'ボーダーパネル', '適合システム: XS50P. PP製. 壁際処理でフロアーパネルと壁の隙間埋めに使用します。切断し易く、パネル下の配線等も見易いメッシュ形状になっています。切断した部分を裏返してパネル裏にはめ込めば補強脚となり、残材が少なくてすみます。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=XS50-BP', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 248, 44.5, 152);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'XS-TCS-', 'タイルカーペット', 'XSシステムの床仕上げ材として使用します。タイルカーペット、ビニルタイル裏には配線ピットに合わせた溝カバーパネル(鋼板)が貼ってあり、フロアーパネルに載せるだけ。カーペットとカーペットの継ぎ目の配線取出口より簡単にケーブルを引き出すことも可能です。組成: B・C・Fナイロン100%. バッキング: 塩ビ樹脂+ガラス繊維布. 寸法: 50cm×50cm. パイル長: 3.5mm ループパイル. 全厚: 6.5mm. 重さ: 約1.3kg (溝カバーパネルAS: 126g, 溝カバーパネルB: 133g). 規格: 1/10ゲージ 13ステッチ. 制電性: 人体帯電圧1KV以下 JIS-L-1021 (20℃ 20%RH合成ゴム底). 防汚性: 防汚糸+フッ素系樹脂による防汚加工。H: 8.8. ※□□内にはタイルカーペット、ビニルタイルの色番が入ります。色見本帳にてご確認ください。※幹線パネル付近の施工用等に溝力バーパネルを一部取付けない変則貼りも受注品として承ります。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=XS-TCS-', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 500, 6.5, 500);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'XS-BTS-', 'ビニルタイル', 'XSシステムの床仕上げ材として使用します。タイルカーペット、ビニルタイル裏には配線ピットに合わせた溝カバーパネル(鋼板)が貼ってあり、フロアーパネルに載せるだけ。カーペットとカーペットの継ぎ目の配線取出口より簡単にケーブルを引き出すことも可能です。寸法: 50cm×50cm. 全厚: 5mm. 重さ: 約2.1kg. 制電性: 表面抵抗値1.2×10^10Ω 体積抵抗値3.8×10^8Ω (JIS A 1453 23) 人体耐電圧0.3KV (JIS L 1021-16準拠)。H: 7.3. ※□□内にはタイルカーペット、ビニルタイルの色番が入ります。色見本帳にてご確認ください。※幹線パネル付近の施工用等に溝力バーパネルを一部取付けない変則貼りも受注品として承ります。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=XS-BTS-', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 500, 5, 500);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'XS-RTP-HD', '十字タイル', '溶融亜鉛めっき. 適合システム: 全サイズ. タイルカーペット裏側の溝カバーパネル(鋼板)の代わりに使用します。壁際にタイルカーペットを施工する際に、裏側に溝カバーパネル(鋼板)の付いていないカーペットと合わせて使用すれば溝カバーパネル(鋼板)をはがす等の手間をかけずに施工できます。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=XS-RTP-HD', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 498, 8, 498);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'XS40-IP-T2', '幹線パネル', '適合システム: XS40P. PP製. 配電盤等からの大容量ケーブルを効率良く収納し、配線ピット内に振り分けます。余剰配線の収納や幹線としての大量配線を可能にしました。フロアーパネルと同サイズのパネルを下地床に敷くだけですから、施工が簡単で、パネルのズレもありません。重量(パネル1枚): 約430g. H: 34.5.', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=XS40-IP-T2', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 500, 34.5, 450);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'XS50-IP-T2', '幹線パネル', '適合システム: XS50P. PP製. 配電盤等からの大容量ケーブルを効率良く収納し、配線ピット内に振り分けます。余剰配線の収納や幹線としての大量配線を可能にしました。フロアーパネルと同サイズのパネルを下地床に敷くだけですから、施工が簡単で、パネルのズレもありません。重量(パネル1枚): 約500g. H: 44.5.', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=XS50-IP-T2', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 500, 44.5, 450);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'XS-IP-C', '幹線カバー', '適合: 幹線パネル(全サイズ). スチール製(厚み: 3.2mm). 裏面: 不織布(ポリエステル)付. 幹線パネルのカバーとして使用します。重量: 4400g.', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=XS-IP-C', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 420, 3.2, 420);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'XS40-IP-D', '幹線パネル用台座', '適合幹線パネル: XS40-IP-T2. PP製. 高さ調整シート付. 架橋高発泡PE製. 幹線パネルを切断加工した場合の幹線カバー支持脚として、また、幹線パネルの上に重量物を置く場合等の補強脚として使用します。H: 29.', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=XS40-IP-D', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 141, 29, 20);
