INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'ZT-3P2B', 'OAフロアコンセント', '二重床(フリーアクセスフロア)内のころがしコンセントとして使用します。コンセントが特殊形状ではない為、市販のOAタップ、延長コード、家電、パソコン等に使用できます。(接地型プラグ、接地無プラグ兼用タイプ), プラグ抜け止めによりプラグ抜けによる不慮の事故を防止します。送り機能付。差し込みコネクタを使用しないでダイレクトで送れます。定格:コンセント部:AC 125V 16A, 送り回路部:AC 125V 20A対応, Fケーブル抜け止め防止付', 2760, 'https://dummyimage.com/200x200/cccccc/000.png&text=ZT-3P2B', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 50, 28, 93.5);
