INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'TK-F40', 'スポンジ (40mm厚)', '4種類のスポンジを施工に合わせて挿入するだけの簡単施工。40mm厚、10mm厚には20mm間隔で切れ目が入っているので切断加工も簡単です。スポンジ(圧縮パック)を切ると厚さが10㎜程度膨らんですき間を埋めますので狭いすき間への施工が簡単です。スポンジ(クロススリット)はスリットがたくさん入っているので、配管等の凹凸にフィットしやすくなっています。壁中空壁片面壁床共通部材。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=TK-F40', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 65, 200, 40);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'TK-F10', 'スポンジ (10mm厚)', '4種類のスポンジを施工に合わせて挿入するだけの簡単施工。40mm厚、10mm厚には20mm間隔で切れ目が入っているので切断加工も簡単です。スポンジ(圧縮パック)を切ると厚さが10㎜程度膨らんですき間を埋めますので狭いすき間への施工が簡単です。スポンジ(クロススリット)はスリットがたくさん入っているので、配管等の凹凸にフィットしやすくなっています。壁中空壁片面壁床共通部材。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=TK-F10', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 65, 200, 10);
