INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MTKB-35JS', 'タイカブラック® 耐火スリーブ (樹脂製耐火スリーブ)', '軽量な樹脂製スリーブで、本体自体が熱膨張材料なので、スリーブ内の耐火材が不要です。切断・バリ取りが不要ですから、鉄管を使用する場合に比べ、飛躍的に作業がラクに行えます。ケーブルを傷つけない樹脂製ですから、保護のブッシングも不要です。', 620, 'https://dummyimage.com/200x200/cccccc/000.png&text=MTKB-35JS', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 35, 35, 200);
