INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MTKB-FP', '不燃パテ', '耐火スリーブと壁との隙間埋めに使用します。隙間に注入しやすいハンドタイプです。500g入。グレー色。水溶性。', 1760, 'https://dummyimage.com/200x200/cccccc/000.png&text=MTKB-FP', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'ADT-50', 'アルミダクトテープ', '耐火スリーブとケーブルとのテーピングに使用します。耐熱性・耐候性・耐寒性に優れたアルミ箔粘着テープです。使用温度:5~60℃。剥離紙付は、必要な長さだけカットして使用する場合に便利です。アルミ箔/厚み:0.05mm。', 4900, 'https://dummyimage.com/200x200/cccccc/000.png&text=ADT-50', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 50, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'ADT-N50', 'アルミダクトテープ', '耐火スリーブとケーブルとのテーピングに使用します。耐熱性・耐候性・耐寒性に優れたアルミ箔粘着テープです。使用温度:5~60℃。剥離紙無。アルミ箔/厚み:0.05mm。', 4380, 'https://dummyimage.com/200x200/cccccc/000.png&text=ADT-N50', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 50, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MTKB-S15M', 'タイカブラック® 耐火シート (メッシュ付)', '配管に巻き付けるだけの簡単施工です! メッシュ付はスライドできるので、配管が固定されていても施工できます。中空壁の場合、開口補強が不要です。床貫通の場合は、施工が床上から可能です。シートだけのシンプル部材! 壁・床のどちらにも使用できる万能な防火部材です。軽量なので持ち運びにも便利です。施工がシンプルなので仕上がりが安定しています! シート状の為、規定量を確実に施工できます。2倍以上にふくらみ、延焼を防止! 300℃以上の熱を受けると、2倍以上にふくらみ延焼を防止します。加工が少なく、廃材、ホコリもほとんど出ません!', 890, 'https://dummyimage.com/200x200/cccccc/000.png&text=MTKB-S15M', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 64, 154, 1.5);
