INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MTKB-R38K15', '壁用鋼製スリーブ', '壁・中空壁共通部材。開口部に鋼製スリーブを施工し、配管と鋼製スリーブのすき間にロックウールを差し込む。重ね代を調整することで開口に合わせた設置が可能。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=MTKB-R38K15', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 150, 100, 300);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'ADT-50', 'アルミダクトテープ', '剥離紙付アルミ箔粘着テープ。厚み0.05mm。PS060WL-1116-1の施工に使用。耐熱性・耐候性・耐寒性に優れる。使用温度:5~60℃。必要な長さだけカットして使用。', 4900, 'https://dummyimage.com/200x200/cccccc/000.png&text=ADT-50', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 50, NULL, 0.05);
